const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

app.post('/api/wallet/create', async (req, res) => {
  const { ninNumber, faceLivelinessRef } = req.body;

  if (!ninNumber) {
    return res.status(400).json({ error: 'ninNumber is required' });
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: ninNumber },
      {
        headers: {
          'app-id': PREMBLY_APP_ID,
          'x-api-key': PREMBLY_API_KEY,
        },
      }
    );

    // Assuming Prembly returns a success field or status in the response
    // based on the requirement "If the NIN is valid"
    // Usually these APIs return status: true or similar.
    // If axios doesn't throw, it's a 2xx response.
    if (response.data && (response.data.status === true || response.data.status === 'success' || response.status === 200)) {
      return res.status(201).json({ wallet_id: 'new_wallet_123' });
    } else {
      return res.status(400).json({ error: 'NIN verification failed' });
    }
  } catch (error) {
    console.error('Prembly API Error:', error.response ? error.response.data : error.message);
    return res.status(400).json({ error: 'NIN verification failed' });
  }
});

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

